const dot=document.getElementById("cursorDot"),outline=document.getElementById("cursorOutline");let mouseX=0,mouseY=0,outlineX=0,outlineY=0;function animateOutline(){outlineX+=.12*(mouseX-outlineX),outlineY+=.12*(mouseY-outlineY),outline.style.left=outlineX+"px",outline.style.top=outlineY+"px",requestAnimationFrame(animateOutline)}document.addEventListener("mousemove",e=>{mouseX=e.clientX,mouseY=e.clientY,dot.style.left=mouseX+"px",dot.style.top=mouseY+"px"}),animateOutline();const interactives=document.querySelectorAll("a, button, .project-card, .skill-pill, .contact-card, .stat-card");interactives.forEach(e=>{e.addEventListener("mouseenter",()=>{dot.classList.add("active"),outline.classList.add("active")}),e.addEventListener("mouseleave",()=>{dot.classList.remove("active"),outline.classList.remove("active")})});